var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"흐음……. 이 끈적거리고 불쾌한 공기…….","JPN":"ふーん……このねっとりした不快な空気……","ENG":"Hmm... This suffocating and unpleasant air...","TWN":"嗯……這黏膩不愉快的空氣……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"확실히 맥크레디 영지는 살기 좋은 곳이 아니네.","JPN":"確かにマクレディー領地は住みやすいところではないわね。","ENG":"Guess the MacCready Estate is not such a pleasant place to live.","TWN":"麥克蕾蒂領地確實不適合居住。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"며칠만 지내도 머리가 이상해지겠어.","JPN":"何日か過ごしただけで頭がおかしくなりそう。","ENG":"Just staying here for a couple of days might make anyone go nuts.","TWN":"只是生活幾天，腦袋就該變得奇怪了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 주민들의 모습은 보이지 않는군요.","JPN":"やはり住民の姿は見当たりませんわ。","ENG":"I do not see any signs of the residents.","TWN":"果然看不到居民們的影子呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"처음 돌아왔을 때보다 더 삭막해졌어요.","JPN":"最初に戻ってきた時よりもの寂しくなっています。","ENG":"It has become more desolate than when I had first arrived.","TWN":"比剛回來時更淒涼了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에이. 무슨 소리야, 레지나.","JPN":"え～？　何言ってるんだよ、レジーナ。","ENG":"C'mon. What are you talking about, Regina?","TWN":"哎呀，你說什麼呢，蕾佳娜。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"우리 오기만 목이 빠져라 기다리던 사람들이 있는 것 같은데.","JPN":"アタシたちのことを首を長くして待ってた人たちがいるみたいだけど。","ENG":"I think I see some who are eagerly awaiting our return.","TWN":"好像有人正望眼欲穿地等著我們回來呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하, 학회원 분들이에요……","JPN":"が、学会員の方々です……","ENG":"I-it's the Society members...","TWN":"是…是學會成員……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 뒤로 숨으세요. 우리 중 가장 노리기 쉬운 사람은 당신입니다.","JPN":"私の後ろに隠れてください。私たちの中でもっとも狙われやすいのはあなたです。","ENG":"Hide behind me. You are the easiest to target out of all of us.","TWN":"躲到我後面，我們當中最容易被盯上的人就是你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오해하지 마십시오. 법학부는 불필요한 무력을 사용하진 않습니다.","JPN":"誤解しないでください。法学部は不要な武力は使いません。","ENG":"Don't be alarmed. The Law Department doesn't use unnecessary force.","TWN":"請不要誤會。法學院不會使用不必要的武力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"집행에 순응한다면 충돌도 없어요.","JPN":"執行に応じれば衝突は避けられます。","ENG":"If you surrender, there will be no bloodshed.","TWN":"只要你們配合，也不會有衝突。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저, 저건……","JPN":"あ、あれは……","ENG":"Th-that's...","TWN":"那…那是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"법학부장.","JPN":"法学部長。","ENG":"The Dean of Law.","TWN":"法學院院長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이런, 큰일났네.","JPN":"まあ、大変。","ENG":"Yikes. We're in trouble now.","TWN":"哎呀，糟了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지금이라도 도망쳐야 하지 않을까요, 부학회장님.","JPN":"今からでも逃げた方がいいのではないでしょうか、副学会長。","ENG":"Don't you think we should run, Ms. Vice President?","TWN":"現在是不是應該逃跑，副學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠? 여기서 물러서면 다음이 없어요.","JPN":"どうしてですか？　ここで引き下がれば次はありません。","ENG":"Why would we? There is nowhere to run from here.","TWN":"為什麼呢？如果就此退下，就再沒有下次了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"저 애랑 붙어도 마찬가지니까.","JPN":"あの子と戦っても同じです。","ENG":"Because it'll all end here if we fight her.","TWN":"因為和她對上也是一樣的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"법학부장 자리에 요구되는 소양은 크게 두 가지랍니다.","JPN":"法学部長に要求される素養は、大きく二つあります。","ENG":"There are two requirements for being the Dean of Law.","TWN":"法學院院長一職的基本要求有兩點。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하나는 국제적으로 활동할 수 있는 법률 지식.","JPN":"一つは国際的に活動することができる法律の知識。","ENG":"One is being fluent in legal knowledge to operate internationally.","TWN":"一個是可以勝任國際活動的法律知識。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 다른 하나는 처형인으로서의 무력.","JPN":"そしてもう一つは処刑人としての武力。","ENG":"And the other is to have brute strength to execute anyone.","TWN":"另一個就是身為行刑人的武力值。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님이 알아듣기 쉽게 풀자면, 관리국이 지정한 S급 카운터는 단독으로 상대할 수 있어야 해요.","JPN":"副学会長にわかりやすいように話しますと、管理局が指定したS級カウンターは単独で相手することができなければなりません。","ENG":"In layman's terms, one must be able to single-handedly defeat a Grade S Counter designated by the Administration.","TWN":"用副學會長能聽懂的話簡單地解釋起來就是，必須可以單獨對付管理局指定的S級制裁者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 저 애는, 역대 법학부장 중에서도 최연소죠.","JPN":"そしてあの子は、歴代の法学部長でも最年少です。","ENG":"And it just happens to be that she... is the youngest person to become the Dean of Law.","TWN":"而且，她還是歷任法學院院長中，最年輕的一個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"종교학부장은 물러나세요.","JPN":"宗教学部長は下がってください。","ENG":"Dean of Religion, you stay out of this.","TWN":"宗教學院院長，請讓開。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이 이상 관여하면 협력자로 판단하겠습니다.","JPN":"これ以上関与すれば、協力者であると判断します。","ENG":"If you continue to be involved, I will consider you an accomplice as well.","TWN":"你繼續參與的話，我會認定你也是幫手。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"흐음, 빠져나갈 여지를 주는 거야? 고마운걸.","JPN":"ふーん、逃げるチャンスをくれるのかしら。ありがたいわね。","ENG":"Hmm... You're giving me a way out? How thoughtful of you.","TWN":"嗯，你這是在給我溜走的機會嗎？真是要謝謝你呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…그래서 고분고분 빠지겠다는 건가요?","JPN":"……それで、大人しく抜けようというのですか？","ENG":"So, are you going to listen to her?","TWN":"……所以你要乖乖溜走嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗, 상호간에 득이 되는 방향으로 합의된 거 아니었나요?","JPN":"ふふっ、お互い得する方向で合意したではないですか？","ENG":"Ha ha, didn't we agree to do whatever was in our best interest?","TWN":"呵呵，我們不是已經朝著互相受益的方向達成了協定嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"회동 이후로 처음 뵙는군요, 부학회장님.","JPN":"会合以来ですね、副学会長。","ENG":"I haven't seen you since the last meeting, Ms. Vice President.","TWN":"會議之後這是第一次見面呢，副學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"1408호에서 요양 중이셨다죠? 몸은 어떠십니까?","JPN":"1408号で療養中であると聞きました。お体の具合はいかがですか？","ENG":"I heard you were on retreat at room 1408. Are you feeling any better?","TWN":"聽說你在1408號休養？身體怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"건강은 여전히 좋지 않아요.","JPN":"相変わらずよくありませんわ。","ENG":"I am still recovering.","TWN":"身體還是不好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 부득이하게 시설을 나왔습니다. 할일이 있거든요.","JPN":"ですが、やむを得ず施設から出ました。やるべきことがありますから。","ENG":"But I had to leave that place to do something.","TWN":"不過我不得不離開設施。因為我有事要做。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회장 대행의 전언에 따라, 부학회장님의 권한은 한시적으로 중단된 상태입니다.","JPN":"学会長代行の伝言により、副学会長の権限は一時的に中断されている状態です。","ENG":"Under the Acting President's authority, all of your authorization has been temporarily revoked.","TWN":"根據代理學會長的口信，副學會長的許可權處於暫停狀態。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저희와 가시죠. 사안에 대해서는 학회장님과 직접 얘기하세요.","JPN":"私たちと一緒に来てください。事案については、学会長と直接お話しください。","ENG":"Please come with me. You should talk with the President yourself of this matter.","TWN":"請跟我們走吧。有什麼事，你直接和學會長談吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죄송하지만 그 요구는 받아들일 수 없습니다, 법학부장.","JPN":"申し訳ありませんが、その要求には応じられません。法学部長。","ENG":"I am afraid I cannot, Dean of Law.","TWN":"很抱歉，我不能答應同意你的要求，法學院院長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델…. 아니, 학회장의 계획은 학회에 큰 타격을 입힐 수 있습니다.","JPN":"エデル……いいえ、学会長の計画は学会に大きな被害をもたらす可能性がありますわ。","ENG":"Edel's, I mean, the President's plan can lay devastating effects to the Society.","TWN":"艾瑟兒……啊不，我是說，學會長的計畫可能會給學會造成巨大打擊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회는 어둠 속에 남아 있어야 온전하게 기능하는 조직이에요.","JPN":"学会は闇の中にあってこそ、まともに機能する組織です。","ENG":"The Society can only thrive when it is hidden in darkness.","TWN":"學會只有留在黑暗中，才能發揮完整的作用。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"합중국을 공격하기로 결정한 시점에서 학회장은 그 선을 넘었습니다.","JPN":"合衆国を攻撃すると決めた時点で、学会長は行き過ぎました。","ENG":"But when the President decided to declare war on the States, she has already crossed that line.","TWN":"在決定攻擊合眾國的那一刻，學會長就越線了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"회동 때와 다르게 조직의 안위를 걱정할 줄 알게 되셨군요.","JPN":"会合の時とは違って、組織の行く末を気遣われるようになりましたね。","ENG":"It's unexpected for you to express concern about the Society when you were attempting to dissolve it at our last meeting.","TWN":"和會議時不同，你已經學會擔心組織的安危了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"하지만 학회장은 필요에 따라 학회를 움직일 권한이 있습니다.","JPN":"ですが、学会長は必要に応じて学会を動かす権限を持っています。","ENG":"Nevertheless, the Society can be mobilized by the President's authorization.","TWN":"不過學會長有權根據需要調動學會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그것이 학회의 규정입니다. 부학회장님의 독단으로 바꿀 수 있는 사안이 아니에요.","JPN":"それが学会の規定です。副学会長の独断で変えられる事案ではありません。","ENG":"That is the Society's rule. This is not an issue that you, the Vice President, can make on your own.","TWN":"這是學會的規定。不是副學會長可以擅自改變的事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저를 학회장에게 끌고 가는 것도 규정에 따른 판단인가요?","JPN":"私を学会長のところに連れて行くのも規定による判断ですか？","ENG":"Are you also taking me to the President as per the rules?","TWN":"把我帶到學會長那裡，也是在基於規定做出的判斷嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"권한이 정지된 학회원의 처우는 법학부가 결정합니다.","JPN":"権限が停止された学会員の処遇は、法学部が決めます。","ENG":"The Law Department is responsible for a Society member whose privileges have been revoked.","TWN":"被暫停許可權的學會成員，由法學院決定如何處置。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇죠. 하지만 학회의 규정에 따르면 학부장 이상은 사정 청취가 우선일 텐데요.","JPN":"そうですわね。ですが学会の規定によりますと、学部長以上は事情聴取が先であるはずです。","ENG":"Yes. However, the Society's rules require a preliminary hearing for any member higher than a dean.","TWN":"是吧。不過根據學會的規定，如果物件是學院院長以上的人，應該先聽取事情的緣由吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"프리드웬의 시설에서 법학부는 본 적 없습니다.","JPN":"プリドウェンの施設で法学部は見かけませんでした。","ENG":"I have not seen the Law Department at Prydwen's facility.","TWN":"我在普利多溫的設施裡沒看到法學院。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 갑자기 학회장을 지원하려고 들죠?","JPN":"どうして突然学会長の肩を持つようになったのですか？","ENG":"Why are you suddenly aiding the President?","TWN":"你為什麼突然要支持學會長？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 영지로 오리라는 건…… 어떻게 예상했습니까?","JPN":"私が領地に来ると……どうしてわかったのですか？","ENG":"And how did you know... that I was going to return to the estate?","TWN":"我會來領地的事……你又是怎麼猜到的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"질문에 답변드려야 할 의무는 없군요, 부학회장님.","JPN":"質問にお答えする義務はありません、副学会長。","ENG":"I have no obligation to answer your questions, Ms. Vice President.","TWN":"我沒有義務回答你的問題，副學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"마지막 권고입니다. 협조적으로 나와 주시죠.","JPN":"最終勧告です。ご協力を期待します。","ENG":"This is your last chance. Please be cooperative.","TWN":"這是最後一次勸告，請你配合。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"해 볼 테면 해 보세요. 람다 스파타리.","JPN":"やれるものならやってみなさい。ラムダ・スパタリー。","ENG":"Try me, if you will, Lamda Spatari.","TWN":"想動手就儘管試試看，蘭達·史派特。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"미리 말씀드리지만, 저도 쉽게 당해 줄 생각은 없어요.","JPN":"先に話しておきますが、私もそう簡単にやられるつもりはありません。","ENG":"Just so you know, I will not be going easy on you.","TWN":"不過我先聲明，我也不會乖乖等著挨打。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};